        fn session_sender() -> ReplyTo {
            ReplyTo::to(ReplyTarget::Session(SessionToken(Uuid::nil())))
        }

        fn decode_reply<K: Kind + DeserializeOwned>(rx: &Receiver<EgressEvent>) -> K {
            let event = rx
                .recv_timeout(Duration::from_secs(2))
                .expect("test: egress event arrives within deadline");
            let EgressEvent::ToSession {
                kind_name, payload, ..
            } = event
            else {
                panic!("expected ToSession egress, got {event:?}");
            };
            assert_eq!(kind_name, K::NAME);
            postcard::from_bytes(&payload).expect("test: reply payload decodes via postcard")
        }

        fn nb_request(model: &str, aspect_ratio: AspectRatio) -> NanobananaGenerate {
            NanobananaGenerate {
                request_id: 1,
                model: model.to_string(),
                prompt: "a cat".to_string(),
                aspect_ratio,
                image_size: None,
                thinking_level: None,
                include_thoughts: None,
                object_reference_paths: Vec::new(),
                character_reference_paths: Vec::new(),
                use_grounding: None,
            }
        }

        #[test]
        fn capability_boots_and_registers_mailbox() {
            let (registry, mailer) = fresh_substrate();
            let chassis = Builder::<TestChassis>::new(Arc::clone(&registry), Arc::clone(&mailer))
                .with_actor::<GeminiCapability>(GeminiConfig::default())
                .build_passive()
                .expect("gemini capability boots");
            assert!(
                registry.lookup(GeminiCapability::NAMESPACE).is_some(),
                "gemini mailbox registered"
            );
            drop(chassis);
        }

        /// The stub Nano Banana adapter stages a real PNG to a scratch
        /// root and the staged path exists + decodes. Drives the staging
        /// helper directly with an explicit root (no process-env
        /// mutation, so no cross-test race) — the cap's landing handler
        /// just re-replies the result enum.
        #[test]
        fn gemini_stub_nanobanana() {
            let scratch = env::temp_dir().join(format!(
                "aether-gemini-nb-{}-{}",
                process::id(),
                request_nonce()
            ));
            fs::create_dir_all(&scratch).expect("scratch dir creates");

            // Stage the stub PNG under the scratch root (the path the
            // cap's ephemeral thread would have produced).
            let staged = stage_gen_output_under(&scratch, STUB_PNG, "png")
                .expect("staging the stub png");
            assert!(staged.starts_with("gen/"));
            assert_eq!(staged.rsplit('.').next(), Some("png"));
            // The path exists under the scratch root and decodes (PNG
            // signature round-trips).
            let bytes = fs::read(scratch.join(&staged)).expect("staged file exists on disk");
            assert_eq!(&bytes[..8], &STUB_PNG[..8]);

            // The cap's landing handler re-replies the result enum to
            // the original caller.
            let (mailer, rx) = test_mailer_and_rx();
            let cap_mailbox = MailboxId(0);
            let mut cap = GeminiCapability::from_parts(
                Arc::new(StubGeminiAdapter),
                Arc::clone(&mailer),
                cap_mailbox,
                4,
            );
            let transport =
                Arc::new(NativeBinding::new_for_test(Arc::clone(&mailer), cap_mailbox));
            let mut ctx = NativeCtx::new(
                &transport,
                session_sender(),
                aether_data::MailId::NONE,
                aether_data::MailId::NONE,
            );
            cap.on_nanobanana_generate(
                &mut ctx,
                nb_request("gemini-3.1-flash-image-preview", AspectRatio::AR_1_1),
            );
            let mut landing_ctx = NativeCtx::new(
                &transport,
                session_sender(),
                aether_data::MailId::NONE,
                aether_data::MailId::NONE,
            );
            cap.on_nanobanana_result(
                &mut landing_ctx,
                NanobananaGenerateResult::Ok {
                    request_id: 1,
                    output_path: staged.clone(),
                    model_used: "gemini-3.1-flash-image-preview".to_string(),
                    usage: aether_kinds::Usage {
                        input_tokens: 0,
                        output_tokens: 0,
                        wall_clock_ms: 0,
                        cost_micros: None,
                    },
                    thought_signature: None,
                    grounding: None,
                },
            );
            match decode_reply::<NanobananaGenerateResult>(&rx) {
                NanobananaGenerateResult::Ok { output_path, .. } => {
                    assert_eq!(output_path, staged);
                }
                other @ NanobananaGenerateResult::Err { .. } => panic!("expected Ok, got {other:?}"),
            }

            let _ = fs::remove_dir_all(&scratch);
        }

        /// Per-model validation: an unsupported aspect ratio / image
        /// size / over-count reference combo errors before any dispatch.
        #[test]
        fn gemini_nanobanana_per_model_validation() {
            let (mailer, rx) = test_mailer_and_rx();
            let cap_mailbox = MailboxId(0);
            let mut cap = GeminiCapability::from_parts(
                Arc::new(StubGeminiAdapter),
                Arc::clone(&mailer),
                cap_mailbox,
                4,
            );
            let transport =
                Arc::new(NativeBinding::new_for_test(Arc::clone(&mailer), cap_mailbox));
            let mut ctx = NativeCtx::new(
                &transport,
                session_sender(),
                aether_data::MailId::NONE,
                aether_data::MailId::NONE,
            );
            // NB1 + the NB2-only extreme aspect ratio -> rejected.
            cap.on_nanobanana_generate(
                &mut ctx,
                nb_request("gemini-2.5-flash-image", AspectRatio::AR_8_1),
            );
            match decode_reply::<NanobananaGenerateResult>(&rx) {
                NanobananaGenerateResult::Err {
                    error: GeminiError::AspectRatioNotSupportedByModel { .. },
                    ..
                } => {}
                other => panic!("expected AspectRatioNotSupportedByModel, got {other:?}"),
            }
            // No dispatch happened — the synchronous validation error
            // never spawned work.
            assert_eq!(cap.test_in_flight(), 0);

            // NB1 + an unsupported image size -> rejected.
            let mut req = nb_request("gemini-2.5-flash-image", AspectRatio::AR_1_1);
            req.image_size = Some(ImageSize::S512);
            cap.on_nanobanana_generate(&mut ctx, req);
            match decode_reply::<NanobananaGenerateResult>(&rx) {
                NanobananaGenerateResult::Err {
                    error: GeminiError::ImageSizeNotSupportedByModel { .. },
                    ..
                } => {}
                other => panic!("expected ImageSizeNotSupportedByModel, got {other:?}"),
            }
        }

        #[test]
        fn gemini_unknown_model_errors() {
            let (mailer, rx) = test_mailer_and_rx();
            let cap_mailbox = MailboxId(0);
            let mut cap = GeminiCapability::from_parts(
                Arc::new(StubGeminiAdapter),
                Arc::clone(&mailer),
                cap_mailbox,
                4,
            );
            let transport =
                Arc::new(NativeBinding::new_for_test(Arc::clone(&mailer), cap_mailbox));
            let mut ctx = NativeCtx::new(
                &transport,
                session_sender(),
                aether_data::MailId::NONE,
                aether_data::MailId::NONE,
            );
            cap.on_nanobanana_generate(&mut ctx, nb_request("gemini-bogus", AspectRatio::AR_1_1));
            match decode_reply::<NanobananaGenerateResult>(&rx) {
                NanobananaGenerateResult::Err {
                    error: GeminiError::UnknownModel { model, supported },
                    ..
                } => {
                    assert_eq!(model, "gemini-bogus");
                    assert!(supported.contains(&"gemini-3.1-flash-image-preview".to_string()));
                }
                other => panic!("expected UnknownModel, got {other:?}"),
            }
        }

        /// Lyria stub stages WAV clips; the `Ok` reply carries one path
        /// per clip.
        #[test]
        fn gemini_stub_lyria() {
            let (mailer, rx) = test_mailer_and_rx();
            let cap_mailbox = MailboxId(0);
            let mut cap = GeminiCapability::from_parts(
                Arc::new(StubGeminiAdapter),
                Arc::clone(&mailer),
                cap_mailbox,
                4,
            );
            let transport =
                Arc::new(NativeBinding::new_for_test(Arc::clone(&mailer), cap_mailbox));
            let mut ctx = NativeCtx::new(
                &transport,
                session_sender(),
                aether_data::MailId::NONE,
                aether_data::MailId::NONE,
            );
            cap.on_lyria_generate(
                &mut ctx,
                LyriaGenerate {
                    request_id: 2,
                    model: "lyria-3".to_string(),
                    prompt: "ambient".to_string(),
                    negative_prompt: None,
                    seed: None,
                    sample_count: Some(2),
                },
            );
            // Drive the landing with two staged WAV paths (the shape the
            // ephemeral thread would have produced). The staging round-
            // trip itself is covered by the staging unit tests; here we
            // assert the landing handler echoes both paths.
            let p1 = "gen/clip-one.wav".to_string();
            let p2 = "gen/clip-two.wav".to_string();
            let mut landing_ctx = NativeCtx::new(
                &transport,
                session_sender(),
                aether_data::MailId::NONE,
                aether_data::MailId::NONE,
            );
            cap.on_lyria_result(
                &mut landing_ctx,
                LyriaGenerateResult::Ok {
                    request_id: 2,
                    output_paths: vec![p1, p2],
                    model_used: "lyria-3".to_string(),
                    usage: aether_kinds::Usage {
                        input_tokens: 0,
                        output_tokens: 0,
                        wall_clock_ms: 0,
                        cost_micros: None,
                    },
                },
            );
            match decode_reply::<LyriaGenerateResult>(&rx) {
                LyriaGenerateResult::Ok { output_paths, .. } => {
                    assert_eq!(output_paths.len(), 2);
                    assert!(output_paths.iter().all(|p| p.rsplit('.').next() == Some("wav")));
                }
                other @ LyriaGenerateResult::Err { .. } => panic!("expected Ok, got {other:?}"),
            }
        }

