        fn request_nonce() -> u64 {
            SystemTime::now().duration_since(UNIX_EPOCH).map_or(0, |d| {
                #[allow(clippy::cast_possible_truncation)]
                let n = d.as_nanos() as u64;
                n
            })
        }
